{
  "claims": [
    {
      "claim_text": "Assemblymember Jacqui Irwin's legislation AB 2426 requires sellers of digital goods to disclose that consumers are only receiving a license to use the digital media."
    },
    {
      "claim_text": "The legislation aims to address consumer protection issues stemming from the revocation of access to digital media purchases."
    },
    {
      "claim_text": "Consumers around the world may lose access to digital media purchases without notice."
    },
    {
      "claim_text": "AB 2426 makes California the first state to officially recognize that the use of terms like 'buy' and 'purchase' for digital media licenses constitutes false advertising."
    },
    {
      "claim_text": "A white paper published by the Department of Commerce’s Internet Policy Task Force in 2016 concluded that consumers would benefit from more information regarding the nature of their transactions for digital media."
    },
    {
      "claim_text": "AB 2426 implements recommendations from the Internet Policy Task Force's 2016 report for consumers engaging in the digital marketplace."
    },
    {
      "claim_text": "Sellers of digital goods that offer permanent offline downloads will be exempt from the need to provide a disclosure about the nature of the purchase."
    },
    {
      "claim_text": "In 2024, video game publisher Ubisoft revoked licenses for purchases of its video game 'The Crew', leaving consumers without access."
    },
    {
      "claim_text": "In 2023, Sony threatened to revoke access to Discovery TV shows but later reached an agreement following consumer backlash."
    },
    {
      "claim_text": "Sony's PlayStation Store permanently revoked access to hundreds of purchased movies in Germany and Austria."
    }
  ]
}
